var e=[{id:`L2_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`긴급 경고!`,JPN:`緊急警告！`,ENG:`Emergency alert!`,TWN:`緊急報告！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`적 리플레이서 병력 및 침식체 일부가 함선 내부로 침입했습니다!`,JPN:`敵のリプレイサー兵力及び侵食体の一部が艦船内部に侵入しました！`,ENG:`Enemy Replacer troops and C.O.'s have breached the hull!`,TWN:`敵人克隆集團的兵力和一部分的侵蝕體侵入了艦船內部！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`함내 전투인원은 즉시 교전수칙에 따라 방어전을 준비하시기 바랍니다!`,JPN:`艦内の戦闘隊員はただちに交戦規則に
基づいて、防御戦に備えてください！`,ENG:`All hands on deck prepare to defend the ship in accordance with applicable rules of engagement!`,TWN:`艦內的作戰人員立刻遵照交戰守則，做好戰鬥準備！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`반복합니다......!`,JPN:`繰り返します……！`,ENG:`I repeat!`,TWN:`重複一次……！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`제길....... 너도 일어나!`,JPN:`くそっ、あんたも立ち上がりなさいよ！`,ENG:`Dang it.. Get up!`,TWN:`可惡……妳也給我起來！`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`BISHOP_REPLACER_REGEN_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`BISHOP_REPLACER_REGEN_NULL`,text:{KOREA:`일어나다니? 뭘 하려는 거지?`,JPN:`立ち上がる？　何をするつもりだ？`,ENG:`Get up? What do you intend to do?`,TWN:`起來？妳想做什麼？`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`BISHOP_REPLACER_REGEN_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`방금 들었잖아?`,JPN:`今の聞いたでしょ？`,ENG:`You heard ‘em!`,TWN:`妳剛剛不是聽到了嗎？`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BISHOP_REPLACER_REGEN_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`놈들의 목적은 당연히 너겠지. 곧 여기로 올 거다.`,JPN:`やつらの目的は当然あんたでしょうよ。間もなくここに来る。`,ENG:`They’re obviously coming for you. They’ll be here anytime now.`,TWN:`那些傢伙們的目標是妳。馬上到這裡來。`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BISHOP_REPLACER_REGEN_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`손님 맞을 준비를 해야지.`,JPN:`お客さんを迎える準備をしないと。`,ENG:`We have to prepare to welcome our guests.`,TWN:`我們得準備迎接客人才行。`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BISHOP_REPLACER_REGEN_NULL`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`BISHOP_REPLACER_REGEN_NULL`,text:{KOREA:`하지만...... 이제 좌표 해석이 얼마 남지 않았다.`,JPN:`だが……もうちょっとで座標がわかるのに。`,ENG:`But... The analysis will be completed soon.`,TWN:`但是……座標還差一點就可以破解出來了。`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BISHOP_REPLACER_REGEN_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L14_1`,type:`dialog`,speaker:`BISHOP_REPLACER_REGEN_NULL`,text:{KOREA:`지금 손을 떼면 그동안의 노력이 모두 물거품이 될 거다.`,JPN:`今手を離せば、これまでの努力がすべて水の泡だ。`,ENG:`If we unlock our hands now, our efforts will have been in vain.`,TWN:`現在鬆手的話，之前的努力都白費了。`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BISHOP_REPLACER_REGEN_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`......그래서 어쩌라고? 이대로 가만히 앉아서 당하자고?`,JPN:`……じゃあ、どうしろって？　このまま成す術もなくやられるわけ？`,ENG:`So what are we supposed to do? Just sit here and let them get to us?`,TWN:`……所以妳要怎樣？就坐在這裡等死嗎？`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BISHOP_REPLACER_REGEN_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`칫, 벌써......?!`,JPN:`チッ、もう……！？`,ENG:`Crap... Already?!`,TWN:`切，已經……？`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`REPLACER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`뭐, 뭐야?`,JPN:`な、何？`,ENG:`W-what the?`,TWN:`怎、怎麼回事？`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`BISHOP_REPLACER_REGEN_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L32_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`......뭘 꾸물거리는 거야? 당장 나와!`,JPN:`……何をぐずぐずしているのよ。今すぐ出てきなさいよ！`,ENG:`What are you waiting for? Get out of there right now!`,TWN:`……妳慢吞吞地在做什麼？馬上給我出來！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};